import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';
import { MathJaxContext } from 'better-react-mathjax';

// 🔧 IMPORTANT : Import du fichier CSS pour l'impression
import './styles/print.css';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const config = {
  tex: {
    inlineMath: [
      ["$", "$"],
      ["\\(", "\\)"],
    ],
    displayMath: [
      ["$$", "$$"],
      ["\\[", "\\]"],
    ],
  },
  svg: {
    fontCache: 'global' // Améliore les performances de rendu SVG
  },
};

const root = createRoot(rootElement);
root.render(
  <React.StrictMode>
    {/* Utilisation explicite de MathJax 4 via CDN */}
    <MathJaxContext 
      config={config}
      src="https://cdn.jsdelivr.net/npm/mathjax@4.0.0-beta.7/tex-svg.js"
    >
      <App />
    </MathJaxContext>
  </React.StrictMode>
);

import React, { useRef, useCallback, useId, useMemo } from 'react';

interface AnswerSpaceProps {
  height?: number;
  onHeightChange: (newHeight: number) => void;
}

// Configuration
const MM_TO_PX = 3.7795275591;
const GRID_SIZE_MM = 5;
const GRID_SIZE_PX = GRID_SIZE_MM * MM_TO_PX;
const MIN_HEIGHT = 40;
// Augmentation significative de la hauteur max pour permettre de toucher le bas de page
const MAX_HEIGHT = 1600; 

// Palette Seyes douce et harmonieuse
const THEME = {
  screen: {
    bg: '#fefdf8',
    gridLine: '#e8e4da',
    dot: '#d5d0c3',
    border: '#e5e1d5',
  },
  print: {
    bg: '#fefbf0',
    gridLine: '#d8d2c0',
    dot: '#cec8b8',
  },
};

const AnswerSpace: React.FC<AnswerSpaceProps> = ({ height = 120, onHeightChange }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const isResizing = useRef(false);
  const startY = useRef(0);
  const startHeight = useRef(0);
  const rafId = useRef<number>(0);

  // ID unique pour les patterns SVG
  const uid = useId().replace(/:/g, '');
  const gridPatternId = `grid-${uid}`;

  // Calcul optimisé du nombre de lignes (mémorisé)
  const gridDimensions = useMemo(() => {
    const cols = Math.ceil(180 / GRID_SIZE_MM) + 1;
    const rows = Math.floor(height / GRID_SIZE_PX) + 1;
    return { cols, rows };
  }, [height]);

  // Calcul de la nouvelle hauteur avec snapping
  const calculateHeight = useCallback((clientY: number): number => {
    const delta = clientY - startY.current;
    const rawHeight = startHeight.current + delta;
    const snapped = Math.round(rawHeight / GRID_SIZE_PX) * GRID_SIZE_PX;
    return Math.max(MIN_HEIGHT, Math.min(MAX_HEIGHT, snapped));
  }, []);

  // Mise à jour fluide avec RAF
  const handleMove = useCallback((clientY: number) => {
    if (!isResizing.current) return;

    cancelAnimationFrame(rafId.current);
    rafId.current = requestAnimationFrame(() => {
      onHeightChange(calculateHeight(clientY));
    });
  }, [calculateHeight, onHeightChange]);

  // Nettoyage des listeners
  const cleanup = useCallback(() => {
    isResizing.current = false;
    cancelAnimationFrame(rafId.current);
    document.body.style.cursor = '';
    document.body.style.userSelect = '';
  }, []);

  // Mouse events
  const handleMouseMove = useCallback((e: MouseEvent) => handleMove(e.clientY), [handleMove]);
  const handleMouseUp = useCallback(() => {
    cleanup();
    window.removeEventListener('mousemove', handleMouseMove);
    window.removeEventListener('mouseup', handleMouseUp);
  }, [cleanup, handleMouseMove]);

  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    e.preventDefault();
    if (!containerRef.current) return;

    isResizing.current = true;
    startY.current = e.clientY;
    startHeight.current = containerRef.current.offsetHeight;
    document.body.style.cursor = 'row-resize';
    document.body.style.userSelect = 'none';

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
  }, [handleMouseMove, handleMouseUp]);

  // Touch events
  const handleTouchMove = useCallback((e: TouchEvent) => {
    if (e.touches.length === 1) {
      e.preventDefault();
      handleMove(e.touches[0].clientY);
    }
  }, [handleMove]);

  const handleTouchEnd = useCallback(() => {
    cleanup();
    window.removeEventListener('touchmove', handleTouchMove);
    window.removeEventListener('touchend', handleTouchEnd);
  }, [cleanup, handleTouchMove]);

  const handleTouchStart = useCallback((e: React.TouchEvent) => {
    if (!containerRef.current || e.touches.length !== 1) return;

    isResizing.current = true;
    startY.current = e.touches[0].clientY;
    startHeight.current = containerRef.current.offsetHeight;

    window.addEventListener('touchmove', handleTouchMove, { passive: false });
    window.addEventListener('touchend', handleTouchEnd);
  }, [handleTouchMove, handleTouchEnd]);

  return (
    <div className="my-3 answer-space group">
      <div
        ref={containerRef}
        className="w-full relative rounded-lg transition-shadow duration-200 hover:shadow-md print:rounded-none print:shadow-none print:border-none"
        style={{
          height: `${height}px`,
          backgroundColor: THEME.screen.bg,
          border: `1px solid ${THEME.screen.border}`,
          overflow: 'hidden',
        }}
      >
        {/* ═══════════════════════════════════════════════════════════════
            SVG GRILLE - VERSION ÉCRAN (Pattern pour performance)
        ═══════════════════════════════════════════════════════════════ */}
        <svg
          className="absolute inset-0 w-full h-full pointer-events-none print:hidden"
          xmlns="http://www.w3.org/2000/svg"
          aria-hidden="true"
          style={{ overflow: 'hidden' }}
        >
          <defs>
            <pattern
              id={gridPatternId}
              width={GRID_SIZE_PX}
              height={GRID_SIZE_PX}
              patternUnits="userSpaceOnUse"
            >
              <rect width="100%" height="100%" fill={THEME.screen.bg} />
              {/* Ligne verticale */}
              <line
                x1={GRID_SIZE_PX}
                y1="0"
                x2={GRID_SIZE_PX}
                y2={GRID_SIZE_PX}
                stroke={THEME.screen.gridLine}
                strokeWidth="0.6"
              />
              {/* Ligne horizontale */}
              <line
                x1="0"
                y1={GRID_SIZE_PX}
                x2={GRID_SIZE_PX}
                y2={GRID_SIZE_PX}
                stroke={THEME.screen.gridLine}
                strokeWidth="0.6"
              />
              {/* Point d'intersection */}
              <circle
                cx={GRID_SIZE_PX}
                cy={GRID_SIZE_PX}
                r="0.8"
                fill={THEME.screen.dot}
              />
            </pattern>
          </defs>
          <rect width="100%" height="100%" fill={`url(#${gridPatternId})`} />
        </svg>

        {/* ═══════════════════════════════════════════════════════════════
            SVG GRILLE - VERSION IMPRESSION (Lignes explicites)
            Seyes doux avec couleurs harmonieuses
        ═══════════════════════════════════════════════════════════════ */}
        <svg
          className="absolute inset-0 w-full h-full pointer-events-none hidden print:block"
          xmlns="http://www.w3.org/2000/svg"
          aria-hidden="true"
          style={{
            overflow: 'hidden',
            shapeRendering: 'crispEdges',
          }}
        >
          {/* Fond crème doux */}
          <rect width="100%" height="100%" fill={THEME.print.bg} />

          {/* Lignes verticales */}
          {Array.from({ length: gridDimensions.cols }, (_, i) => (
            <line
              key={`v${i}`}
              x1={i * GRID_SIZE_PX}
              y1="0"
              x2={i * GRID_SIZE_PX}
              y2={height}
              stroke={THEME.print.gridLine}
              strokeWidth="0.5"
            />
          ))}

          {/* Lignes horizontales */}
          {Array.from({ length: gridDimensions.rows }, (_, i) => (
            <line
              key={`h${i}`}
              x1="0"
              y1={i * GRID_SIZE_PX}
              x2="100%"
              y2={i * GRID_SIZE_PX}
              stroke={THEME.print.gridLine}
              strokeWidth="0.5"
            />
          ))}

          {/* Points aux intersections */}
          {Array.from({ length: gridDimensions.cols }, (_, col) =>
            Array.from({ length: gridDimensions.rows }, (_, row) => (
              <circle
                key={`p${col}-${row}`}
                cx={col * GRID_SIZE_PX}
                cy={row * GRID_SIZE_PX}
                r="0.6"
                fill={THEME.print.dot}
              />
            ))
          )}
        </svg>

        {/* Poignée de redimensionnement */}
        <div
          className="absolute bottom-0 left-0 w-full h-5 cursor-row-resize z-10 flex items-end justify-center pb-1 opacity-0 group-hover:opacity-100 transition-opacity duration-150 no-print"
          onMouseDown={handleMouseDown}
          onTouchStart={handleTouchStart}
          role="slider"
          aria-label="Ajuster la hauteur"
          aria-valuemin={MIN_HEIGHT}
          aria-valuemax={MAX_HEIGHT}
          aria-valuenow={height}
          tabIndex={0}
        >
          <div className="flex flex-col items-center gap-0.5">
            <div className="w-12 h-1 bg-amber-600/40 rounded-full hover:bg-amber-600/60 transition-colors" />
            <div className="w-8 h-0.5 bg-amber-600/25 rounded-full" />
          </div>
        </div>

        {/* Indicateur de hauteur */}
        <div className="absolute top-1.5 right-1.5 px-1.5 py-0.5 text-[10px] font-mono bg-black/60 text-white rounded opacity-0 group-hover:opacity-100 transition-opacity no-print select-none">
          {height}px
        </div>
      </div>
    </div>
  );
};

export default AnswerSpace;

/**
 * styles/print.css
 * Optimisation haute résolution pour impression PDF
 */

@media print {
  /* ═══════════════════════════════════════════════════════════════
     CONFIGURATION GLOBALE
  ═══════════════════════════════════════════════════════════════ */
  :root {
    color-scheme: light;
  }

  * {
    -webkit-print-color-adjust: exact !important;
    print-color-adjust: exact !important;
    box-shadow: none !important;
    text-shadow: none !important;
  }

  /* Marges de page optimisées - moins de marge en bas */
  @page {
    size: A4 portrait;
    margin: 12mm 15mm 8mm 15mm; /* haut droite bas gauche */
  }

  @page :first {
    margin-top: 10mm; /* Moins de marge en haut sur la 1ère page */
  }

  html, body {
    margin: 0 !important;
    padding: 0 !important;
    background: white !important;
    color: #000000 !important;
    font-size: 11pt;
    line-height: 1.4;
    text-rendering: optimizeLegibility;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }

  /* ═══════════════════════════════════════════════════════════════
     MASQUAGE DES ÉLÉMENTS D'INTERFACE
  ═══════════════════════════════════════════════════════════════ */
  .no-print,
  header,
  button,
  .cursor-row-resize,
  [role="button"],
  [role="slider"],
  .fixed,
  ::-webkit-scrollbar {
    display: none !important;
  }

  /* ═══════════════════════════════════════════════════════════════
     LAYOUT PRINCIPAL
  ═══════════════════════════════════════════════════════════════ */
  main.container {
    max-width: 100% !important;
    width: 100% !important;
    padding: 0 !important;
    margin: 0 !important;
  }

  /* Réduire les espacements verticaux */
  .space-y-10 {
    gap: 4mm !important;
  }

  .space-y-8 {
    gap: 3mm !important;
  }

  /* ═══════════════════════════════════════════════════════════════
     TYPOGRAPHIE
  ═══════════════════════════════════════════════════════════════ */
  h1, h2, h3, h4, h5, h6, p, span, div, li, strong, em, .prose, .prose * {
    color: #000000 !important;
    background-color: transparent !important;
  }

  h1 {
    margin-top: 0 !important;
    padding-top: 0 !important;
    margin-bottom: 3mm !important;
  }

  /* MathJax en noir pur */
  mjx-container[jax="SVG"] {
    display: inline-block !important;
  }

  mjx-container[jax="SVG"] * {
    stroke: #000000 !important;
    fill: #000000 !important;
  }

  /* Badge Exercice */
  .exercise-badge {
    border: 1pt solid #000000 !important;
    background-color: transparent !important;
    color: #000000 !important;
    padding: 1mm 3mm !important;
    border-radius: 1mm !important;
    font-weight: bold !important;
  }

  /* ═══════════════════════════════════════════════════════════════
     PREMIÈRE PAGE - GARDER TITRE + CONTENU ENSEMBLE
  ═══════════════════════════════════════════════════════════════ */
  .title-and-first-exercise-container {
    page-break-inside: avoid !important;
    break-inside: avoid !important;
    page-break-after: auto !important;
  }

  /* S'assurer que l'en-tête (classe + année) reste avec le titre */
  .title-and-first-exercise-container > div:first-child {
    page-break-after: avoid !important;
    break-after: avoid !important;
  }

  /* Le titre principal ne doit pas être seul */
  .title-and-first-exercise-container .text-center {
    page-break-after: avoid !important;
    break-after: avoid !important;
  }

  /* ═══════════════════════════════════════════════════════════════
     ZONES DE RÉPONSE - STYLE SEYES DOUX OPTIMISÉ
     Bordure fine cohérente et espacement amélioré
  ═══════════════════════════════════════════════════════════════ */
  .answer-space {
    margin-top: 6mm !important; /* Espacement augmenté entre la question et la zone */
    margin-bottom: 3mm !important;
    page-break-inside: avoid !important;
    break-inside: avoid !important;
  }

  .answer-space > div {
    /* Bordure Standard Fine (1pt Noir) - Cohérente avec le texte */
    border: 1pt solid #000000 !important; 
    border-radius: 4px !important;
    background-color: transparent !important; /* Fond blanc standard */
    background-image: none !important;
    box-shadow: none !important;
    overflow: hidden !important;
  }

  /* Masquer le SVG écran, afficher le SVG print */
  .answer-space svg.print\:hidden {
    display: none !important;
  }

  .answer-space svg.hidden.print\:block,
  .answer-space svg.hidden {
    display: block !important;
  }

  /* SVG haute qualité */
  .answer-space svg {
    display: block !important;
    overflow: hidden !important;
    opacity: 1 !important;
    shape-rendering: crispEdges !important;
  }

  /* Lignes de grille Seyes douces - couleur beige harmonieuse */
  .answer-space svg line {
    stroke: #d8d2c0 !important;
    stroke-width: 0.4pt !important;
  }

  /* Points d'intersection discrets */
  .answer-space svg circle {
    fill: #cec8b8 !important;
  }

  /* Fond crème doux */
  .answer-space svg rect:first-of-type {
    fill: #fefbf0 !important;
  }

  /* ═══════════════════════════════════════════════════════════════
     RÈGLES SVG GÉNÉRALES
  ═══════════════════════════════════════════════════════════════ */
  svg {
    display: block !important;
    overflow: visible !important;
    max-width: 100% !important;
    shape-rendering: geometricPrecision !important;
  }

  img {
    image-rendering: high-quality;
    -ms-interpolation-mode: bicubic;
  }

  /* ═══════════════════════════════════════════════════════════════
     EXERCICES - GESTION DES SAUTS DE PAGE
  ═══════════════════════════════════════════════════════════════ */
  .exercise-card {
    page-break-inside: auto !important;
    break-inside: auto !important;
    margin-bottom: 4mm !important;
    border: none !important;
    padding: 0 !important;
  }

  /* Titre d'exercice ne doit pas être seul en bas de page */
  .exercise-card h2 {
    page-break-after: avoid !important;
    break-after: avoid !important;
    margin-bottom: 2mm !important;
  }

  /* Énoncé collé à ce qui suit */
  .exercise-statement {
    page-break-inside: avoid !important;
    break-inside: avoid !important;
    page-break-after: avoid !important;
    break-after: avoid !important;
    margin-bottom: 2mm !important;
  }

  /* Questions */
  .question-block {
    page-break-inside: avoid !important;
    break-inside: avoid !important;
    margin-bottom: 2mm !important;
  }

