import React, { useState, useRef, useEffect } from 'react';
import type { Worksheet, WorksheetContent } from '../types';
import { GripVertical, Trash2, X, UploadCloud, ImageOff, Info, Image, LayoutTemplate, ListOrdered } from 'lucide-react';

const CLASS_OPTIONS = [
	'Tronc Commun Scientifique',
	"1ère Bac Sciences Expérimentales",
	"1ère Bac Sciences Mathématiques",
	"2ème Bac Sciences Expérimentales",
	"2ème Bac Sciences Mathématiques",
];

const ACCEPTED_LOGO_TYPES = ['image/png', 'image/jpeg', 'image/svg+xml'];
const MAX_LOGO_SIZE_BYTES = 2 * 1024 * 1024; // 2 Mo

const computeDefaultSchoolYear = (): string => {
	const now = new Date();
	const year = now.getFullYear();
	const month = now.getMonth(); // 0-11
	const startYear = month >= 7 ? year : year - 1;
	return `${startYear}-${startYear + 1}`;
};

interface SettingsModalProps {
	isOpen: boolean;
	onClose: () => void;
	worksheet: Worksheet;
	onSave: (updatedContent: WorksheetContent) => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, worksheet, onSave }) => {
	const [editableContent, setEditableContent] = useState<WorksheetContent>(JSON.parse(JSON.stringify(worksheet.content)));
	const [logoError, setLogoError] = useState<string | null>(null);
	const [isLogoDragOver, setIsLogoDragOver] = useState(false);
	const draggedItem = useRef<number | null>(null);
	const draggedOverItem = useRef<number | null>(null);
	const logoInputRef = useRef<HTMLInputElement>(null);

		useEffect(() => {
			if (!isOpen) {
				return;
			}
			const cloned: WorksheetContent = JSON.parse(JSON.stringify(worksheet.content));
			const defaultYear = computeDefaultSchoolYear();
			const settings = { ...(cloned.settings ?? {}) };
			if (!settings.schoolYear) {
				settings.schoolYear = defaultYear;
			}
			cloned.settings = settings;
			setEditableContent(cloned);
			setLogoError(null);
			setIsLogoDragOver(false);
		}, [worksheet, isOpen]);

	if (!isOpen) {
		return null;
	}

	const handleClassChange = (value: string) => {
		setEditableContent(prev => ({
			...prev,
			settings: {
				...prev.settings,
				className: value || undefined,
			},
		}));
	};

		const handleSchoolYearChange = (value: string) => {
			const normalized = value.trim();
			const resolvedValue = normalized === '' ? computeDefaultSchoolYear() : value;
			setEditableContent(prev => ({
				...prev,
				settings: {
					...prev.settings,
					schoolYear: resolvedValue,
				},
			}));
	};

	const handleHeightChange = (e: React.ChangeEvent<HTMLInputElement>) => {
		const newHeight = parseInt(e.target.value, 10);
		setEditableContent(prev => ({
			...prev,
			settings: { ...prev.settings, answerSpaceMinHeight: newHeight },
		}));
	};

	const handleDeleteExercise = (index: number) => {
		if (window.confirm("Êtes-vous sûr de vouloir supprimer cet exercice ? Cette action est irréversible.")) {
			const newExercises = [...editableContent.exercises];
			newExercises.splice(index, 1);
			setEditableContent(prev => ({ ...prev, exercises: newExercises }));
		}
	};

	const handleDragStart = (e: React.DragEvent<HTMLDivElement>, index: number) => {
		draggedItem.current = index;
		e.dataTransfer.effectAllowed = 'move';
	};

	const handleDragEnter = (_e: React.DragEvent<HTMLDivElement>, index: number) => {
		draggedOverItem.current = index;
	};

	const handleDragEnd = () => {
		draggedItem.current = null;
		draggedOverItem.current = null;
	};

	const handleDrop = () => {
		if (draggedItem.current !== null && draggedOverItem.current !== null && draggedItem.current !== draggedOverItem.current) {
			const newExercises = [...editableContent.exercises];
			const item = newExercises.splice(draggedItem.current, 1)[0];
			newExercises.splice(draggedOverItem.current, 0, item);
			setEditableContent(prev => ({ ...prev, exercises: newExercises }));
		}
		handleDragEnd();
	};

	const handleLogoFile = (file: File) => {
		if (!ACCEPTED_LOGO_TYPES.includes(file.type)) {
			setLogoError('Formats acceptés : PNG, JPG ou SVG.');
			return;
		}
		if (file.size > MAX_LOGO_SIZE_BYTES) {
			setLogoError('Le fichier dépasse la taille maximale de 2 Mo.');
			return;
		}

		const reader = new FileReader();
		reader.onload = () => {
			const result = reader.result;
			if (typeof result === 'string') {
				setEditableContent(prev => ({
					...prev,
					settings: {
						...prev.settings,
						logoDataUrl: result,
					},
				}));
				setLogoError(null);
			} else {
				setLogoError('Impossible de lire ce fichier.');
			}
		};
		reader.onerror = () => {
			setLogoError('Erreur lors de la lecture du fichier.');
		};
		reader.readAsDataURL(file);
	};

	const handleLogoInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
		const file = e.target.files?.[0];
		if (file) {
			handleLogoFile(file);
		}
		e.target.value = '';
	};

	const handleLogoDrop = (e: React.DragEvent<HTMLDivElement>) => {
		e.preventDefault();
		setIsLogoDragOver(false);
		const file = e.dataTransfer.files && e.dataTransfer.files[0];
		if (file) {
			handleLogoFile(file);
		}
	};

	const handleLogoDragOver = (e: React.DragEvent<HTMLDivElement>) => {
		e.preventDefault();
		if (!isLogoDragOver) {
			setIsLogoDragOver(true);
		}
	};

	const handleLogoDragLeave = (e: React.DragEvent<HTMLDivElement>) => {
		e.preventDefault();
		if (isLogoDragOver) {
			setIsLogoDragOver(false);
		}
	};

	const handleRemoveLogo = () => {
		setEditableContent(prev => ({
			...prev,
			settings: {
				...prev.settings,
				logoDataUrl: undefined,
			},
		}));
		setLogoError(null);
	};

	const handleSave = () => {
		const cleanedSettings = editableContent.settings ? { ...editableContent.settings } : {};
		if (!cleanedSettings.className) delete cleanedSettings.className;
		if (!cleanedSettings.schoolYear) delete cleanedSettings.schoolYear;
		if (!cleanedSettings.logoDataUrl) delete cleanedSettings.logoDataUrl;
		if (cleanedSettings.answerSpaceMinHeight === undefined) delete cleanedSettings.answerSpaceMinHeight;

		const finalSettings = Object.keys(cleanedSettings).length > 0 ? cleanedSettings : undefined;

		const contentToSave: WorksheetContent = {
			...editableContent,
			settings: finalSettings,
		};

		onSave(contentToSave);
	};

	const currentSettings = editableContent.settings ?? {};
	const selectedClass = currentSettings.className ?? '';
		const selectedSchoolYear = currentSettings.schoolYear ?? computeDefaultSchoolYear();
	const logoPreview = currentSettings.logoDataUrl;

	return (
		<div
			className="fixed inset-0 bg-black/40 backdrop-blur-sm z-40 flex justify-center items-center p-4"
			onClick={onClose}
			role="dialog"
			aria-modal="true"
		>
			<div
				className="bg-white rounded-xl shadow-2xl border border-slate-200 w-full max-w-2xl max-h-[90vh] flex flex-col"
				onClick={e => e.stopPropagation()}
			>
				<header className="flex justify-between items-center px-6 py-4 border-b border-slate-200">
					<h2 className="text-lg font-bold font-display text-slate-800">Paramètres</h2>
					<button onClick={onClose} className="p-1.5 rounded-md hover:bg-slate-100 transition" aria-label="Fermer">
						<X className="h-5 w-5 text-slate-500" />
					</button>
				</header>

			<main className="p-6 overflow-y-auto text-gray-900 custom-scrollbar">
					<input
						ref={logoInputRef}
						type="file"
						accept={ACCEPTED_LOGO_TYPES.join(',')}
						className="hidden"
						onChange={handleLogoInputChange}
					/>
					<div className="space-y-10">
						{/* Informations Générales */}
						<section className="space-y-4">
							<div className="flex items-start gap-3">
								<div className="p-2 bg-blue-50 text-blue-600 rounded-lg shrink-0">
									<Info className="h-5 w-5" />
								</div>
								<div>
									<h3 className="text-lg font-semibold text-gray-900">Informations générales</h3>
									<p className="text-sm text-slate-500">Ces informations s'afficheront en haut de la fiche imprimée.</p>
								</div>
							</div>
							<div className="grid gap-6 md:grid-cols-2 ml-0 md:ml-12">
								<div>
									  <label htmlFor="class-select" className="block text-sm font-medium text-gray-900 mb-2">Classe</label>
									<select
										id="class-select"
										value={selectedClass}
										onChange={(e) => handleClassChange(e.target.value)}
										className="w-full rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm focus:border-indigo-500 focus:outline-none focus:ring-2 focus:ring-indigo-200 transition"
									>
										<option value="">— Sélectionner —</option>
										{CLASS_OPTIONS.map(option => (
											<option key={option} value={option}>{option}</option>
										))}
									</select>
								</div>
								<div>
									  <label htmlFor="school-year" className="block text-sm font-medium text-gray-900 mb-2">Année scolaire</label>
									<input
										id="school-year"
										type="text"
										placeholder="2025-2026"
										value={selectedSchoolYear}
										onChange={(e) => handleSchoolYearChange(e.target.value)}
										className="w-full rounded-lg border border-gray-300 px-3 py-2 text-sm focus:border-indigo-500 focus:outline-none focus:ring-2 focus:ring-indigo-200 transition"
									/>
								</div>
							</div>
						</section>

						{/* Identité Visuelle */}
						<section className="space-y-4">
							<div className="flex items-start gap-3">
								<div className="p-2 bg-purple-50 text-purple-600 rounded-lg shrink-0">
									<Image className="h-5 w-5" />
								</div>
								<div>
									<h3 className="text-lg font-semibold text-gray-900">Identité visuelle</h3>
									<p className="text-sm text-slate-500">Personnalisez l'en-tête avec votre logo (PNG, JPG ou SVG).</p>
								</div>
							</div>
							<div className="ml-0 md:ml-12">
								<div
									className={`flex flex-col items-center justify-center gap-3 border-2 border-dashed rounded-lg p-6 text-center cursor-pointer transition ${isLogoDragOver ? 'border-indigo-500 bg-indigo-50 text-indigo-600' : 'border-gray-300 bg-gray-50 hover:border-indigo-400 hover:bg-indigo-50'}`}
									onClick={() => logoInputRef.current?.click()}
									onDrop={handleLogoDrop}
									onDragOver={handleLogoDragOver}
									onDragLeave={handleLogoDragLeave}
									role="button"
									tabIndex={0}
									onKeyDown={(e) => {
										if (e.key === 'Enter' || e.key === ' ') {
											e.preventDefault();
											logoInputRef.current?.click();
										}
									}}
									aria-label="Zone de dépôt pour le logo"
								>
									<UploadCloud className="h-8 w-8" />
									<div>
										<p className="text-sm font-semibold">Glissez-déposez votre logo ici</p>
										<p className="text-xs text-gray-500 mt-1">ou cliquez pour parcourir vos fichiers</p>
									</div>
									{logoPreview && (
										<div className="mt-4 w-full max-w-xs rounded-md border border-gray-200 bg-white p-3 relative group">
											<img src={logoPreview} alt="Logo téléchargé" className="mx-auto max-h-32 w-full object-contain" />
										</div>
									)}
								</div>
								{logoError && <p className="text-sm text-red-600 mt-2">{logoError}</p>}
								{logoPreview && (
									<button
										type="button"
										onClick={handleRemoveLogo}
										className="mt-3 inline-flex items-center gap-2 rounded-lg border border-gray-300 px-3 py-1.5 text-xs font-medium text-gray-600 hover:border-red-400 hover:text-red-500 hover:bg-red-50 transition"
									>
										<ImageOff className="h-3.5 w-3.5" />
										Retirer le logo
									</button>
								)}
							</div>
						</section>

						{/* Zones de réponse */}
						<section className="space-y-4">
							<div className="flex items-start gap-3">
								<div className="p-2 bg-amber-50 text-amber-600 rounded-lg shrink-0">
									<LayoutTemplate className="h-5 w-5" />
								</div>
								<div>
									<h3 className="text-lg font-semibold text-gray-900">Zones de réponse</h3>
									<p className="text-sm text-slate-500">Hauteur par défaut des zones quadrillées.</p>
								</div>
							</div>
							<div className="flex items-center gap-4 ml-0 md:ml-12 bg-white p-4 rounded-lg border border-slate-200">
								<input
									id="answer-height"
									type="range"
									min="50"
									max="750"
									step="10"
									value={editableContent.settings?.answerSpaceMinHeight || 120}
									onChange={handleHeightChange}
									className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
								/>
								<label htmlFor="answer-height" className="font-mono font-bold text-indigo-600 w-16 text-center text-lg">
									{editableContent.settings?.answerSpaceMinHeight || 120}px
								</label>
							</div>
						</section>

						{/* Organisation */}
						<section className="space-y-4">
							<div className="flex items-start gap-3">
								<div className="p-2 bg-emerald-50 text-emerald-600 rounded-lg shrink-0">
									<ListOrdered className="h-5 w-5" />
								</div>
								<div>
									<h3 className="text-lg font-semibold text-gray-900">Organisation des exercices</h3>
									<p className="text-sm text-slate-500">Réordonnez ou supprimez des exercices.</p>
								</div>
							</div>
							<div className="space-y-2 ml-0 md:ml-12">
								{editableContent.exercises.map((ex, index) => (
									<div
										key={ex.id || index}
										className="flex items-center justify-between p-3 bg-white border border-gray-200 rounded-lg hover:border-indigo-300 hover:shadow-sm transition group"
										draggable
										onDragStart={(e) => handleDragStart(e, index)}
										onDragEnter={(e) => handleDragEnter(e, index)}
										onDragOver={(e) => e.preventDefault()}
										onDrop={handleDrop}
										onDragEnd={handleDragEnd}
									>
										<div className="flex items-center gap-3">
											<div className="p-1 text-gray-300 group-hover:text-indigo-400 cursor-move transition">
												<GripVertical className="h-5 w-5" />
											</div>
											<span className="font-medium text-slate-700 truncate">{index + 1}. {ex.title}</span>
										</div>
										<button
											onClick={() => handleDeleteExercise(index)}
											  className="p-2 text-slate-400 hover:text-red-600 rounded-full hover:bg-red-50 transition"
											aria-label="Supprimer l'exercice"
										>
											<Trash2 className="h-4 w-4" />
										</button>
									</div>
								))}
							</div>
						</section>
					</div>
				</main>

			<footer className="flex justify-end items-center gap-2.5 px-6 py-4 border-t border-slate-200 bg-slate-50/50 rounded-b-xl">
					<button onClick={onClose} className="px-4 py-2 text-sm text-slate-600 bg-white border border-slate-200 rounded-lg hover:bg-slate-50 font-medium transition shadow-sm">
						Annuler
					</button>
					<button onClick={handleSave} className="px-4 py-2 text-sm text-white bg-slate-900 rounded-lg hover:bg-slate-800 font-medium transition shadow-md hover:shadow-lg">
						Enregistrer
					</button>
				</footer>
			</div>
		</div>
	);
};

export default SettingsModal;

/**
 * styles/print.css
 * High-Resolution A4 Print — badges match screen exactly
 */

@media print {

  /* ── Resolution & color fidelity ── */
  :root {
    color-scheme: light;
    --print-font-size: 10.5pt;
    --print-line-height: 1.5;
  }

  * {
    -webkit-print-color-adjust: exact !important;
    print-color-adjust: exact !important;
    box-shadow: none !important;
    text-shadow: none !important;
  }

  @page {
    size: A4 portrait;
    margin: 12mm 14mm 10mm 14mm;
  }

  @page :first {
    margin-top: 8mm;
  }

  html, body {
    margin: 0 !important;
    padding: 0 !important;
    background: white !important;
    color: #000 !important;
    font-size: var(--print-font-size);
    line-height: var(--print-line-height);
    text-rendering: optimizeLegibility;
    -webkit-font-smoothing: subpixel-antialiased;
    font-feature-settings: "kern" 1, "liga" 1;
    image-rendering: high-quality;
  }

  /* ── Hide UI elements ── */
  .no-print,
  header,
  button,
  .cursor-row-resize,
  [role="button"],
  [role="slider"],
  .fixed,
  ::-webkit-scrollbar {
    display: none !important;
  }

  /* ── Layout ── */
  main.container {
    max-width: 100% !important;
    width: 100% !important;
    padding: 0 !important;
    margin: 0 !important;
  }

  .space-y-10 > * + * { margin-top: 5mm !important; }
  .space-y-8 > * + * { margin-top: 3mm !important; }

  /* ── Typography — pure black ── */
  h1, h2, h3, h4, h5, h6, p, span, div, li, strong, em,
  .prose, .prose * {
    color: #000 !important;
    background-color: transparent !important;
  }

  h1 {
    margin-top: 0 !important;
    padding-top: 0 !important;
    margin-bottom: 4mm !important;
    font-size: 18pt !important;
    letter-spacing: -0.01em;
  }

  /* ══════════════════════════════════════════════
     EXERCISE BADGE — COMPACT & TIGHT
  ══════════════════════════════════════════════ */
  .exercise-badge {
    background-color: #000 !important;
    color: #fff !important;
    padding: 0.8mm 2mm !important; /* Serré */
    border-radius: 1mm !important;
    font-weight: 800 !important;
    font-size: 8pt !important;
    letter-spacing: 0.05em !important;
    display: inline-flex !important;
    align-items: center !important;
    line-height: 1 !important;
  }

  /* ESPACE AUGMENTÉ ENTRE TITRE ET CONTENU */
  .exercise-title {
    margin-bottom: 7mm !important; /* Espace significatif */
    font-size: 11pt !important;
    line-height: 1.3 !important;
    display: flex !important;
    align-items: center !important;
    gap: 4mm !important;
    border-bottom: 0.5pt solid #eee !important; /* Petit séparateur chic optionnel */
    padding-bottom: 2mm !important;
  }

  /* ══════════════════════════════════════════════
     QUESTION BADGES — CHIC & PRO STYLE
  ══════════════════════════════════════════════ */
  .question-number-badge {
    /* Reset du style "badge carré" pour l'impression */
    background-color: transparent !important;
    border: none !important;
    color: #000 !important;
    padding: 0 !important;
    border-radius: 0 !important;

    /* Typographie Chic */
    font-family: 'Playfair Display', serif !important;
    font-weight: 700 !important;
    font-size: 11pt !important; /* Même taille que le texte, mais gras/serif */

    /* Layout */
    display: flex !important;
    align-items: flex-start !important;
    justify-content: flex-end !important;
    width: 1.5em !important;
    margin-top: 0 !important;
    flex-shrink: 0 !important;
  }

  /* Ajout d'un point après le numéro pour le style classique */
  .question-number-badge::after {
    content: "." !important;
    margin-left: 1px;
  }

  /* Level 0: Nombres */
  .question-badge-level-0 {
    font-size: 11pt !important;
  }

  /* Level 1: Lettres (a, b...) */
  .question-badge-level-1 {
    font-size: 11pt !important;
    font-style: italic !important; /* Lettres en italique pour le style math */
  }

  /* Pour les lettres, on peut vouloir une parenthèse au lieu d'un point */
  .question-badge-level-1::after {
    content: ")" !important;
  }

  /* ══════════════════════════════════════════════
     QUESTION ROWS — GRID LAYOUT
  ══════════════════════════════════════════════ */
  .question-row {
    display: grid !important;
    grid-template-columns: min-content 1fr !important;
    gap: 3mm !important;
    align-items: start !important;
    page-break-inside: avoid !important;
    break-inside: avoid !important;
  }

  /* ── Question content ── */
  .question-content {
    min-width: 0 !important;
    overflow-wrap: break-word !important;
    font-size: var(--print-font-size) !important;
    line-height: var(--print-line-height) !important;
    padding-top: 0 !important;
  }

  /* ── Question list spacing ── */
  .question-list-main {
    gap: 3mm !important;
    padding-left: 0 !important;
  }

  .question-list-sub {
    gap: 2mm !important;
    padding-left: 5mm !important;
    margin-top: 0 !important;
  }

  .subquestions-container {
    margin-top: 2mm !important;
  }

  /* ══════════════════════════════════════════════
     MATHJAX SVG
  ══════════════════════════════════════════════ */
  mjx-container[jax="SVG"] {
    display: inline !important;
    vertical-align: baseline !important;
  }

  mjx-container[jax="SVG"] svg {
    vertical-align: baseline !important;
  }

  mjx-container[jax="SVG"] * {
    stroke: #000 !important;
    fill: #000 !important;
  }

  mjx-container[display="true"] {
    display: block !important;
    margin: 2mm 0 !important;
    text-align: center !important;
  }

  .question-content mjx-container[jax="SVG"] {
    display: inline !important;
    vertical-align: middle !important;
    max-width: 100% !important;
  }

  .question-content mjx-container[display="true"] {
    display: block !important;
    margin: 1.5mm auto !important;
    max-width: 100% !important;
    overflow-x: visible !important;
  }

  .question-content mjx-container[display="true"] svg {
    max-width: 100% !important;
    height: auto !important;
  }

  /* ══════════════════════════════════════════════
     EXERCISE CARDS — page breaks
  ══════════════════════════════════════════════ */
  .exercise-card {
    page-break-inside: auto !important;
    break-inside: auto !important;
    margin-bottom: 4mm !important;
    border: none !important;
    padding: 0 !important;
  }

  .exercise-card .exercise-title {
    page-break-after: avoid !important;
    break-after: avoid !important;
    /* Margin defined above */
  }

  .exercise-statement {
    page-break-inside: avoid !important;
    break-inside: avoid !important;
    page-break-after: avoid !important;
    break-after: avoid !important;
    margin-bottom: 2mm !important;
    font-size: var(--print-font-size) !important;
  }

  .question-block {
    page-break-inside: avoid !important;
    break-inside: avoid !important;
    margin-bottom: 1.5mm !important;
  }

  .question-block .answer-space {
    page-break-before: avoid !important;
    break-before: avoid !important;
  }

  .exercise-statement + .answer-space {
    page-break-before: avoid !important;
    break-before: avoid !important;
  }

  .exercise-statement + .exercise-questions-wrapper {
    page-break-before: avoid !important;
    break-before: avoid !important;
  }

  .exercise-questions-wrapper {
    margin-top: 2mm !important;
  }

  .exercise-questions-wrapper > .question-list-main > .question-block:first-child {
    page-break-before: avoid !important;
    break-before: avoid !important;
  }

  /* ── Title + first exercise grouping ── */
  .title-and-first-exercise-container {
    page-break-inside: avoid !important;
    break-inside: avoid !important;
  }

  .title-and-first-exercise-container > div:first-child {
    page-break-after: avoid !important;
    break-after: avoid !important;
  }

  .title-and-first-exercise-container .text-center {
    page-break-after: avoid !important;
    break-after: avoid !important;
  }

  /* ══════════════════════════════════════════════
     ANSWER SPACES
  ══════════════════════════════════════════════ */
  .answer-space {
    margin-top: 3mm !important;
    margin-bottom: 2mm !important;
    page-break-inside: avoid !important;
    break-inside: avoid !important;
    width: 100% !important;
  }

  .answer-space > div {
    box-sizing: border-box !important;
    width: 100% !important;
    border: 0.75pt solid #000 !important;
    border-radius: 2pt !important;
    background-color: transparent !important;
    background-image: none !important;
    overflow: hidden !important;
    display: block !important;
  }

  .answer-space svg.print\:hidden {
    display: none !important;
  }

  .answer-space svg.hidden.print\:block,
  .answer-space svg.hidden {
    display: block !important;
    width: 100% !important;
  }

  .answer-space svg {
    display: block !important;
    overflow: hidden !important;
    opacity: 1 !important;
    shape-rendering: crispEdges !important;
  }

  .answer-space svg line {
    stroke: #d8d2c0 !important;
    stroke-width: 0.35pt !important;
  }

  .answer-space svg circle {
    fill: #cec8b8 !important;
  }

  .answer-space svg rect:first-of-type {
    fill: #fefbf0 !important;
  }

  /* ── SVG general ── */
  svg {
    display: block !important;
    overflow: visible !important;
    max-width: 100% !important;
    shape-rendering: geometricPrecision !important;
    image-rendering: optimizeQuality !important;
  }

  img {
    image-rendering: high-quality;
    -ms-interpolation-mode: bicubic;
  }

  /* ── Orphans / widows ── */
  p, li { orphans: 3; widows: 3; }

  .exercise-card:last-of-type {
    page-break-after: auto !important;
  }

  /* ── Prose reset ── */
  .prose {
    font-size: var(--print-font-size) !important;
    line-height: var(--print-line-height) !important;
  }

  .prose p {
    margin-top: 0 !important;
    margin-bottom: 0 !important;
  }
}
